inline const char *espcontrol_i18n(const char *text) {
  if (!text) return "";
  if (espcontrol_language_code() == "cs") return espcontrol_i18n_cs(text);
  if (espcontrol_language_code() == "da") return espcontrol_i18n_da(text);
  if (espcontrol_language_code() == "de") return espcontrol_i18n_de(text);
  if (espcontrol_language_code() == "es") return espcontrol_i18n_es(text);
  if (espcontrol_language_code() == "fr") return espcontrol_i18n_fr(text);
  if (espcontrol_language_code() == "it") return espcontrol_i18n_it(text);
  if (espcontrol_language_code() == "nb") return espcontrol_i18n_nb(text);
  if (espcontrol_language_code() == "nl") return espcontrol_i18n_nl(text);
  if (espcontrol_language_code() == "pl") return espcontrol_i18n_pl(text);
  if (espcontrol_language_code() == "pt-br") return espcontrol_i18n_pt_br(text);
  if (espcontrol_language_code() == "pt") return espcontrol_i18n_pt(text);
  if (espcontrol_language_code() == "sk") return espcontrol_i18n_sk(text);
  if (espcontrol_language_code() == "sv") return espcontrol_i18n_sv(text);
  return text;
}

inline std::string espcontrol_i18n(const std::string &text) {
  return std::string(espcontrol_i18n(text.c_str()));
}
